const { chromium } = require('playwright');
const fs = require('fs');

// =========================
// FULL GEORGIA ZIP STRING
// =========================
const GA_ZIP_STRING =
` `;

// =========================
// AUTO SPLIT EVERY 5 DIGITS
// =========================
const ZIP_CODES = GA_ZIP_STRING.match(/\d{5}/g);

// =========================
// SCRAPE ONE ZIP
// =========================
async function scrapeZip(browser, zipcode) {
  const page = await browser.newPage();

  try {
    console.log(`  Loading incentives for ${zipcode}...`);

    await page.goto('https://www.electricforall.org/rebates-incentives/', {
      waitUntil: 'domcontentloaded'
    });

    await page.fill('input[type="text"]', '');
    await page.fill('input[type="text"]', zipcode);
    await page.keyboard.press('Enter');

    // WAIT UNTIL CARDS STABILIZE
    await page.waitForFunction(() => {
      const section = Array.from(document.querySelectorAll('h2,h3'))
        .find(h => h.innerText?.includes('Charging Station Incentives'));

      if (!section) return false;

      const container = section.parentElement;
      if (!container) return false;

      const cards = Array.from(container.querySelectorAll('button,a'))
        .filter(el => el.innerText?.trim() === 'READ MORE');

      if (!window.__lastCardCount) {
        window.__lastCardCount = cards.length;
        window.__stableSince = Date.now();
        return false;
      }

      if (window.__lastCardCount !== cards.length) {
        window.__lastCardCount = cards.length;
        window.__stableSince = Date.now();
        return false;
      }

      return (
        cards.length > 0 &&
        Date.now() - window.__stableSince > 1500
      );
    }, { timeout: 90000 });

    const incentives = await page.evaluate(() => {
      const section = Array.from(document.querySelectorAll('h2,h3'))
        .find(h => h.innerText?.includes('Charging Station Incentives'));

      if (!section) return '';

      const container = section.parentElement;
      if (!container) return '';

      let text = container.innerText || '';

      return text
        .replace(/READ MORE/g, '')
        .replace(/\n{2,}/g, '\n')
        .replace(/[ \t]+/g, ' ')
        .trim();
    });

    await page.close();
    return incentives;

  } catch (err) {
    await page.close();
    throw err;
  }
}

// =========================
// MAIN
// =========================
(async () => {
  let results = {};

  if (fs.existsSync('results.json')) {
    try {
      results = JSON.parse(fs.readFileSync('results.json'));
      console.log(`Resuming — ${Object.keys(results).length} ZIPs completed`);
    } catch {
      console.log('Corrupted results.json detected — starting fresh');
      results = {};
    }
  }

  const browser = await chromium.launch({ headless: true });

  for (const zip of ZIP_CODES) {
    if (results[zip]) {
      console.log(`Skipping ${zip} (already done)`);
      continue;
    }

    console.log(`Scraping ZIP ${zip}`);

    try {
      results[zip] = await scrapeZip(browser, zip);
      fs.writeFileSync('results.json', JSON.stringify(results, null, 2));
      console.log(`  Saved ${zip}`);
    } catch (err) {
      console.error(`  Failed ${zip}: ${err.message}`);
    }
  }

  await browser.close();
  console.log('All done.');
})();

